def forecast_with_bands(
    forecast: list[float],
    mape: float = 0.20,        # 20% MAPE typical for 30-day GenAI forecasts
) -> list[dict]:
    return [
        {
            "day": i + 1,
            "p50": v,
            "p10": v * (1 - mape * 1.3),  # lower bound
            "p90": v * (1 + mape * 1.3),  # upper bound
        }
        for i, v in enumerate(forecast)
    ]

