from dataclasses import dataclass
from collections import deque
import time

@dataclass
class QuotaMonitor:
    quota_tpm: int
    alert_threshold_pct: float = 0.80
    burn_rate_multiplier: float = 5.0

    def __post_init__(self):
        self._window: deque[tuple[float, int]] = deque()  # (timestamp, tokens)
        self._baseline_tpm: float = 0.0

    def record(self, tokens: int) -> None:
        now = time.monotonic()
        self._window.append((now, tokens))
        # Prune to last 60 seconds
        while self._window and self._window[0][0] < now - 60:
            self._window.popleft()

    @property
    def current_tpm(self) -> int:
        return sum(t for _, t in self._window)

    def check_alerts(self) -> list[str]:
        alerts = []
        tpm = self.current_tpm
        utilization = tpm / self.quota_tpm

        if utilization > self.alert_threshold_pct:
            alerts.append(
                f"QUOTA_ALERT: {utilization:.0%} utilization "
                f"({tpm:,} / {self.quota_tpm:,} TPM)"
            )

        if self._baseline_tpm > 0:
            burn = tpm / self._baseline_tpm
            if burn > self.burn_rate_multiplier:
                alerts.append(
                    f"BURN_RATE_ALERT: {burn:.1f}x normal consumption — "
                    f"possible runaway workload"
                )
        return alerts

    def update_baseline(self, baseline_tpm: float) -> None:
        self._baseline_tpm = baseline_tpm

monitor = QuotaMonitor(quota_tpm=4_000_000)  # Engineering dept pool
monitor.update_baseline(baseline_tpm=800_000)  # typical peak TPM

from dataclasses import dataclass
from typing import Optional
import random

@dataclass
class ProviderPool:
    name: str
    model_id: str
    quota_tpm: int
    weight: float = 1.0
    _current_tpm: int = 0

    @property
    def utilization(self) -> float:
        return self._current_tpm / self.quota_tpm

    @property
    def is_available(self) -> bool:
        return self.utilization < 0.90  # 90% soft ceiling

class QuotaAwareRouter:
    def __init__(self, pools: list[ProviderPool]):
        self.pools = pools

    def select(self, estimated_tokens: int) -> Optional[ProviderPool]:
        available = [p for p in self.pools if p.is_available]
        if not available:
            return None  # all pools saturated — return 429

        # Weighted random selection among available pools
        total_weight = sum(p.weight * (1 - p.utilization) for p in available)
        r = random.random() * total_weight
        cumulative = 0.0
        for pool in available:
            cumulative += pool.weight * (1 - pool.utilization)
            if r <= cumulative:
                return pool
        return available[-1]

# Two providers: OpenAI primary + Anthropic fallback
pools = [
    ProviderPool("openai", "gpt-4o", quota_tpm=6_000_000, weight=2.0),
    ProviderPool("anthropic", "claude-sonnet-4-6", quota_tpm=4_000_000, weight=1.0),
]
router = QuotaAwareRouter(pools)
selected = router.select(estimated_tokens=2000)
if selected:
    print(f"Route to {selected.name} ({selected.utilization:.0%} utilized)")
else:
    print("All pools saturated — serve 429 with Retry-After header")
